Rule.Source:
  Function writeToLog() {
    param([string]$message)
      Add-Content ($(Get-Date -format "yyyy-MM-dd HH:mm:ss") + "::$message") -Path $logFile
  }


  Add-type -path utils.dll
    writeToLog("Start PS Rule")
    $logFile = "C:\Sailpoint\IQService\logs.txt"
    $session = ""

    # Read the environment variables
    $sReader = New-Object System.IO.StringReader([System.String]$env:Request)
    $sResult = New-Object System.IO.StringReader([System.String]$env:Result)

    # Form the xml reader objects
    $xmlReader = [ System.xml.XmlTextReader]([sailpoint.utils.xml.XmlUtil]::getReader($sReader))
    $xmlReader_Result = [ System.xml.XmlTextReader]([sailpoint.utils.xml.XmlUtil]::getReader($sResult))

    # Create SailPoint objects
    $requestObject = New-Object Sailpoint.Utils.objects.AccountRequest($xmlReader)
    $resultObject = New-Object Sailpoint.Utils.objects.ServiceResult($xmlReader_Result)

    # Loop through the attributes from the request
    $atrBaseDN = ""
    $atrDepartmentName = ""
    foreach ($attribute in $requestObject.AttributeRequests)
  {
    if($attribute.Name -eq "baseDN")
    {
      $atrBaseDN=$attribute.value;
      writeToLog("atrBaseDN::$atrBaseDN")  
    }
    if($attribute.Name -eq "departmentName")
    {  
      $atrDepartmentName=$attribute.value;
      writeToLog("atrDepartmentName::$atrDepartmentName")  
    }
  }

 # Credentials and Target
$username = "Eshiam\Administrator"
$password = "Kandula@100"
$securePassword = ConvertTo-SecureString $password -AsPlainText -Force
$credential = New-Object System.Management.Automation.PSCredential($username, $securePassword)
$domainController = "192.168.177.129"

# Target OU details
$ouName = $atrDepartmentName
$ouPath = "OU=Departments,OU=Demo,DC=Eshiam,DC=com"  # Replace with your domain DN
$fullOU = "OU=$ouName,$ouPath"

# Add target to TrustedHosts (only needed if using IP)
Set-Item WSMan:\localhost\Client\TrustedHosts -Value $domainController -Force
Restart-Service WinRM

# Create remote session
$session = New-PSSession -ComputerName $domainController -Credential $credential

# Run logic on remote server
Invoke-Command -Session $session -ScriptBlock {
    param($fullOU, $ouName, $ouPath)

    Import-Module ActiveDirectory


    if (Get-ADOrganizationalUnit -LDAPFilter "(distinguishedName=$fullOU)" -ErrorAction SilentlyContinue) {
           writeToLog("OU already exists")
    } else {
        New-ADOrganizationalUnit -Name $ouName -Path $ouPath -ProtectedFromAccidentalDeletion $true
          writeToLog("OU created successfull.")
    }
} -ArgumentList $fullOU, $ouName, $ouPath

# Clean up session
Remove-PSSession $session


